# src/checkers.py

def initialize_board():
    board = []
    for row in range(8):
        if row < 3:
            board.append(['B' if col % 2 == 0 else ' ' for col in range(8)])
        elif row > 4:
            board.append(['W' if col % 2 == 1 else ' ' for col in range(8)])
        else:
            board.append([' ' for _ in range(8)])
    return board

def print_board(board):
    for row in board:
        print(" ".join(row))

def is_valid_move(board, start, end):
    row_diff = abs(start[0] - end[0])
    col_diff = abs(start[1] - end[1])

    if row_diff not in [1, 2] or col_diff != 1:
        return False

    piece = board[start[0]][start[1]]
    destination = board[end[0]][end[1]]

    if piece == 'B':
        if destination != ' ':
            return False
        if row_diff == 2 and end[0] == start[0] + 2:
            intermediate = ((start[0] + end[0]) // 2, (start[1] + end[1]) // 2)
            if board[intermediate[0]][intermediate[1]] != 'W':
                return False
    elif piece == 'W':
        if destination != ' ':
            return False
        if row_diff == 2 and end[0] == start[0] - 2:
            intermediate = ((start[0] + end[0]) // 2, (start[1] + end[1]) // 2)
            if board[intermediate[0]][intermediate[1]] != 'B':
                return False
    else:
        return False

def move_piece(board, start, end):
    piece = board[start[0]][start[1]]
    board[start[0]][start[1]] = ' '
    board[end[0]][end[1]] = piece

# Example usage
if __name__ == "__main__":
    board = initialize_board()
    print_board(board)
